const matches = $input.first().json.matches || [];

// Format KB context without filenames
const formattedResults = matches.map((match, index) => {
  return `[Result ${index + 1}]\n${match.metadata.chunk_text}\nSource: ${match.metadata.source}\n`;
}).join('\n');

return [{
  json: {
    ...$input.first().json,
    kb_context: formattedResults
  }
}];

const field = 'output'; // change if your chat response field is different
let text = items[0].json[field] ?? '';

// If upstream ever produced literal "\n", normalize it to real newlines
text = text.replace(/\\n/g, '\n');

const sourcesMatch = text.match(/Sources:\s*([\s\S]*)$/i);
if (!sourcesMatch) {
  return [{ json: items[0].json }];
}

// Grab URLs from the Sources section
const sourcesSection = sourcesMatch[1];
let urls = (sourcesSection.match(/https?:\/\/[^\s,]+/g) || []).map(u => u.trim());

// Remove duplicates
urls = [...new Set(urls)];

// Build Markdown list (renders correctly in n8n published chat)
const rebuiltSources =
  'Sources:\n' + urls.map(u => `- ${u}`).join('\n');

// Replace everything from "Sources:" to end with rebuilt block
const formatted = text.replace(/Sources:\s*[\s\S]*$/i, rebuiltSources);

return [{
  json: {
    ...items[0].json,
    [field]: formatted,
  }
}];

